head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 1,
		"chartIntervalCount" : 4,
		"topCnt" : 10
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSZZ3200000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 작업일자 설정한다.
	dmaSearchParam.set("strtDtD" , utilLib.addDay(utilLib.getCurrentDate("yyyyMMdd"), -7));
	dmaSearchParam.set("endDtD" , utilLib.getCurrentDate("yyyyMMdd"));
	dmaSearchParam.set("strtDtM" , utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -1));
	dmaSearchParam.set("endDtM" , utilLib.getCurrentDate("yyyyMM"));

	// 로그인한 사용자 ID 변수설정
	scwin.usrId = comLib.getUsrId();

	// 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
	scwin.setAthrSysDivCd();
};

/**
 * 사용자에게 부여된 권한의 시스템구분코드를 조회한다.
 * @param
 * @return
 */
scwin.setAthrSysDivCd = function () {
	var requestData = {};
	requestData.data = {
		"usrId" : scwin.usrId,
		"sysDivCd" : "SCM_0000"
	};

	var option = {
		action : "sc/authmng/retrieveAthrSysDivCd.do",
		reqData : requestData,
		resData : dltSysDivCdList,
		success : "scwin.retrieveAthrSysDivCdCallback",
		isShowMeg : false
	};
	ajaxLib.requestAjaxSyncCode($p, option);
};

/**
 * 조회 CallBack 실행
 * @param <Object> resBody
 * @return
 */
scwin.retrieveAthrSysDivCdCallback = function (resBody, e) {
	if (dltSysDivCdList.getRowCount() == 0) {
		// 시스템관리자만 접근이 가능합니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00343"), "utilLib.winContainerClose");
		return;
	}

	// 화면 오픈시 자동조회를 한다.
	comLib.setEnterKeyEvent(grpInqire , scwin.btnInqire_onclick);
	scwin.btnInqire_onclick();
};

/**
* 통계 조회를 한다. (사이트 총 방문자 수 데이터 조회)
 * @param
 * @return
*/
scwin.btnInqire_onclick = function() {
	var queryString = "";
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		var strtDate = dmaSearchParam.get("strtDtD");
		var endDate = dmaSearchParam.get("endDtD");

		if (String(strtDate).length != 8 || String(endDate).length != 8) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (utilLib.minusMonths(strtDate, endDate) > 3 ? true : false) {
			// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
			alert(utilLib.getMessage("ECS.INFO.00012", "3개월")[0]);
			return;
		} else if (parseInt(strtDate) > parseInt(endDate)) {
			// 시작년월이 종료년월일보다 클수 없습니다.
			alert(utilLib.getMessage("ECS.INFO.00014")[0]);
			return;
		}

		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtD;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtD;
		queryString += "&cnd=daly";
	} else if (cnd == "M") {
		var strtDate = dmaSearchParam.get("strtDtM");
		var endDate = dmaSearchParam.get("endDtM");

		if (String(strtDate).length != 6 || String(endDate).length != 6) {
			// 조회기간이 올바르지 않습니다.
			alert(utilLib.getMessage("ECS.INFO.00011")[0]);
			return;
		} else if (utilLib.minusYears(strtDate, endDate) > 3 ? true : false) {
			// 조회기간은 {0}을 넘어갈 수 없습니다. 다시 설정해 주세요.
			alert(utilLib.getMessage("ECS.INFO.00012", "3년")[0]);
			return;
		} else if (parseInt(strtDate) > parseInt(endDate)) {
			// 시작년월이 종료년월일보다 클수 없습니다.
			alert(utilLib.getMessage("ECS.INFO.00014")[0]);
			return;
		}

		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtM;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtM;
		queryString += "&cnd=mnby";
	}

	var option = {
		action : "zz/sitestats/retrieve-visitr-cnt-by-dt.do" + queryString,
		method : "get",
		resData : dltVisitrCntByDt,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};

	ajaxLib.executeAjax($p, option);
};

/**
* 통계 조회 콜백 실행 (사이트 총 방문자 수 차트 생성, 메뉴별 방문자 수 데이터 조회)
 * @param <Object> rewsBody
 * @return
*/
scwin.inqireCallback = function (resBody, e) {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerVisitrCntByDt";
	rMateChartH5.create($p.id + "ChartVisitrCntByDt", grpChartVisitrCntByDt.getID(), chartVars, "100%", "100%");

	var queryString = "";
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtD;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtD;
		queryString += "&cnd=daly";
	} else if (cnd == "M") {
		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtM;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtM;
		queryString += "&cnd=mnby";
	}

	var option = {
		action : "zz/sitestats/retrieve-visitr-cnt-by-menu.do" + queryString,
		method : "get",
		resData : dltVisitrCntByMenu,
		success : "scwin.inqireCallback2",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
* 통계 조회 콜백 실행 (메뉴별 방문자 수 차트 생성, 부서별 방문자 수 데이터 조회)
 * @param <Object> rewsBody
 * @return
*/
scwin.inqireCallback2 = function (resBody, e) {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerVisitrCntByMenu";
	rMateChartH5.create($p.id + "ChartVisitrCntByMenu", grpChartVisitrCntByMenu.getID(), chartVars, "100%", "100%");

	var queryString = "";
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtD;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtD;
		queryString += "&cnd=daly";
	} else if (cnd == "M") {
		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtM;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtM;
		queryString += "&cnd=mnby";
	}

	var option = {
		action : "zz/sitestats/retrieve-dept-visitr-cnt-by-dt.do" + queryString,
		method : "get",
		resData : dltDeptVisitrCntByDt,
		success : "scwin.inqireCallback3",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
* 통계 조회 콜백 실행 (부서별 방문자 수 TOP 차트 생성, 월별/년별 총 방문자수 데이터 조회)
 * @param <Object> rewsBody
 * @return
*/
scwin.inqireCallback3 = function (resBody, e) {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerDeptVisitrCntByDt";
	rMateChartH5.create($p.id + "ChartDeptVisitrCntByDt", grpChartDeptVisitrCntByDt.getID(), chartVars, "100%", "98%");

	var queryString = "";
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtD;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtD;
		queryString += "&cnd=daly";
	} else if (cnd == "M") {
		queryString = "?strtDt=" + dmaSearchParam.getJSON().strtDtM;
		queryString += "&endDt=" + dmaSearchParam.getJSON().endDtM;
		queryString += "&cnd=mnby";
	}

	var option = {
		action : "zz/sitestats/retrieve-mt-yy-visitr-cnt-by-dt.do" + queryString,
		method : "get",
		resData : dltMtYyVisitrCntByDt,
		success : "scwin.inqireCallback4",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
* 통계 조회 콜백 실행 (월별/년별 총 방문자수 차트 생성)
 * @param <Object> rewsBody
 * @return
*/
scwin.inqireCallback4 = function (resBody, e) {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerMtYyVisitrCntByDt";
	rMateChartH5.create($p.id + "ChartMtYyVisitrCntByDt", grpChartMtYyVisitrCntByDt.getID(), chartVars, "100%", "100%");
};

/**
 * 라디오버튼 선택에 따라 조회연도를 변경한다.
 * @param
 * @return
 */
scwin.radMdBy_onviewchange = function(info) {
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		grpCalDNm.setStyle("display", "");
		grpCalDBox.setStyle("display", "");
		grpCalMNm.setStyle("display", "none");
		grpCalMBox.setStyle("display", "none");
	} else if (cnd == "M") {
		grpCalDNm.setStyle("display", "none");
		grpCalDBox.setStyle("display", "none");
		grpCalMNm.setStyle("display", "");
		grpCalMBox.setStyle("display", "");
	} else {
		return;
	}
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 사이트 총 방문자 수 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerVisitrCntByDt = function(id) {
	var dlt = dltVisitrCntByDt.getAllJSON();
	var chartList = [];

	for (var data of dlt) {
		chartList.push({
			"dt" : data.dt,
			"cnt" : data.cnt
		});
	};

	var max = dlt.reduce((max, obj) => obj.cnt > max ? obj.cnt : max, 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(max.toFixed(0)).length - 2));
	var interval = Math.ceil((max / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var capText = "";
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		capText = "일";
	} else if (cnd == "M") {
		capText = "월";
	}
	var solidColor = ecsLib.getSkinColors().chartSolidColor2;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+'	<Options>'
		+'		<Caption text="' + capText + '별 방문자 수" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingTop="5" paddingLeft="9.6" fontWeight="bold" fontSize="1rem"/>'
		+'		<Legend position="bottom" direction="vertical" labelPlacement="right" width="70"/>'
		+'	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+'	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+'		<horizontalAxis>'
		+'			<CategoryAxis id="hAxis" categoryField="dt" />'
		+'		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="방문자수"/>'
		+ '		</verticalAxis>'
		+'		<series>'
//		+'			<Column2DSeries color="#666666" labelPosition="outside" label="inqireIemVu" font-weight="bold" yField="inqireIemVu" displayName="방문자">'
		+'			<Column2DSeries color="#666666" label="inqireIemVu" font-weight="bold" yField="cnt" displayName="방문자" rotate="45">'
		+'				<fill>'
		+'					<SolidColor color="' + solidColor + '"/>'
		+'				</fill>'
		+'				<showDataEffect>'
		+'					<SeriesInterpolate/>'
		+'				</showDataEffect>'
		+'			</Column2DSeries>'
		+'		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="true" canStagger="true"/>'
		+ '		</horizontalAxisRenderers>'
		+'	</Column2DChart>'
		+'</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 사이트 총 방문자 수 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerVisitrCntByMenu = function(id) {
	var dlt = dltVisitrCntByMenu.getAllJSON();
	var chartList = [];
	var top = 0;

	for (var data of dlt) {
		if (top < scwin.initData.chart.topCnt) {
			chartList.push({
				"menuNm" : data.menuNm,
				"cnt" : data.cnt
			});
		} else {
			break;
		}
		top++;
	};

	var max = chartList.reduce((max, obj) => obj.cnt > max ? obj.cnt : max, 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(max.toFixed(0)).length - 2));
	var interval = Math.ceil((max / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var capText = "메뉴별 방문수 TOP " + scwin.initData.chart.topCnt;
	var solidColor = ecsLib.getSkinColors().chartSolidColor2;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+'	<Options>'
		+'		<Caption text="' + capText + '" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingTop="5" paddingLeft="9.6" fontWeight="bold" fontSize="1rem"/>'
		+'		<Legend position="bottom" direction="vertical" labelPlacement="right" width="70"/>'
		+'	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+'	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+'		<horizontalAxis>'
		+'			<CategoryAxis id="hAxis" categoryField="menuNm" />'
		+'		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="방문자수"/>'
		+ '		</verticalAxis>'
		+'		<series>'
//		+'			<Column2DSeries color="#666666" labelPosition="outside" label="inqireIemVu" font-weight="bold" yField="inqireIemVu" displayName="방문자">'
		+'			<Column2DSeries color="#666666" label="inqireIemVu" font-weight="bold" yField="cnt" displayName="방문수" rotate="45">'
		+'				<fill>'
		+'					<SolidColor color="' + solidColor + '"/>'
		+'				</fill>'
		+'				<showDataEffect>'
		+'					<SeriesInterpolate/>'
		+'				</showDataEffect>'
		+'			</Column2DSeries>'
		+'		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="true" canStagger="true"/>'
		+ '		</horizontalAxisRenderers>'
		+'	</Column2DChart>'
		+'</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 부서별 방문자 수 TOP 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerDeptVisitrCntByDt = function(id) {
	var dlt = dltDeptVisitrCntByDt.getAllJSON();
	var chartList = [];
	var top = 0;

	var isZero = true;
	for (var data of dlt) {
		if (top < scwin.initData.chart.topCnt) {
			chartList.push({
				"deptNm" : data.deptNm,
				"cnt" : data.cnt
			});
			isZero = false;
		} else {
			break;
		}
		top++;
	};

	var max = chartList.reduce((max, obj) => obj.cnt > max ? obj.cnt : max, 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(max.toFixed(0)).length - 2));
	var interval = Math.ceil((max / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var capText = "부서별 방문자 수 TOP " + scwin.initData.chart.topCnt;
	var solidColor = ecsLib.getSkinColors().chartSolidColor2;

	/* 컬럼 차트
	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+'	<Options>'
		+'		<Caption text="' + capText + '"/>'
		+'		<Legend position="bottom" direction="vertical" labelPlacement="right" width="70"/>'
		+'	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+'	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+'		<horizontalAxis>'
		+'			<CategoryAxis id="hAxis" categoryField="deptNm" />'
		+'		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="방문자수"/>'
		+ '		</verticalAxis>'
		+'		<series>'
//		+'			<Column2DSeries color="#666666" labelPosition="outside" label="inqireIemVu" font-weight="bold" yField="inqireIemVu" displayName="방문자">'
		+'			<Column2DSeries color="#666666" label="inqireIemVu" font-weight="bold" yField="cnt" displayName="방문수" rotate="45">'
		+'				<fill>'
		+'					<SolidColor color="' + solidColor + '"/>'
		+'				</fill>'
		+'				<showDataEffect>'
		+'					<SeriesInterpolate/>'
		+'				</showDataEffect>'
		+'			</Column2DSeries>'
		+'		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="true" canStagger="true"/>'
		+ '		</horizontalAxisRenderers>'
		+'	</Column2DChart>'
		+'</rMateChart>';
	*/

	if (isZero) {
		grpChartDeptVisitrCntByDt_noresult.setStyle("display", "");
	} else {
		grpChartDeptVisitrCntByDt_noresult.setStyle("display", "none");
	}
	var layoutStr =
		'<rMateChart backgroundColor="" cornerRadius="12">'
		+ '	<Options>'
		+ '		<Caption text="' + capText + '" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingTop="5" paddingLeft="9.6" fontWeight="bold" fontSize="1rem"/>'
		+ '		<Legend />'
		+ '	</Options>'
		+ '	<Pie3DChart showDataTips="true" paddingTop="10" paddingBottom="10" paddingRight="15" paddingLeft="15">'
		+ '		<series>'
		+ '			<Pie3DSeries startAngle="28" labelPosition="inside" color="#FAFAFA" fontWeight="bold" nameField="deptNm" field="cnt" labelField="deptNm">'
		+ '				<fills>'
		+ '					<SolidColor color="#7DD2FF" />'
		+ '					<SolidColor color="#FFA0A7" />'
		+ '					<SolidColor color="#FFCA7C" />'
		+ '					<SolidColor color="#D1D1D1" />'
		+ '					<SolidColor color="#9CA5F3" />'
		+ '					<SolidColor color="#68E1CE" />'
		+ '					<SolidColor color="#5554A0" />'
		+ '					<SolidColor color="#834538" />'
		+ '					<SolidColor color="#576F25" />'
		+ '				</fills>'
		+ '				<showDataEffect>'
		+ '					<SeriesSlide duration="1000" />'
		+ '				</showDataEffect>'
		+ '			</Pie3DSeries>'
		+ '			</series>'
		+ '	</Pie3DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};

/**
 * 월별/년별 총 방문자수 차트 설정
 * @param id : 차트 그룹 ID
 */
scwin.chartReadyHandlerMtYyVisitrCntByDt = function(id) {
	var dlt = dltMtYyVisitrCntByDt.getAllJSON();
	var chartList = [];
	var top = 0;

	for (var data of dlt) {
		if (top < 10) {
			chartList.push({
				"dt" : data.dt,
				"cnt" : data.cnt
			});
		} else {
			break;
		}
		top++;
	};

	var max = chartList.reduce((max, obj) => obj.cnt > max ? obj.cnt : max, 0);
	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(max.toFixed(0)).length - 2));
	var interval = Math.ceil((max / scwin.initData.chart.chartIntervalCount) / chartUnit) * chartUnit;

	var capText = " 방문자 수";
	var cnd = radMdBy.getValue();

	if (cnd == "D") {
		capText = "월별" + capText;
	} else if (cnd == "M") {
		capText = "년별" + capText;
	}
	var solidColor = ecsLib.getSkinColors().chartSolidColor2;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" cornerRadius="12">'
		+'	<Options>'
		+'		<Caption text="' + capText + '" textAlign="center" paddingRight="9.6" paddingBottom="9.6" paddingTop="5" paddingLeft="9.6" fontWeight="bold" fontSize="1rem"/>'
		+'		<Legend position="bottom" direction="vertical" labelPlacement="right" width="70"/>'
		+'	</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+'	<Column2DChart showDataTips="true" dataTipDisplayMode="axis" maxColumnWidth="25">'
		+'		<horizontalAxis>'
		+'			<CategoryAxis id="hAxis" categoryField="dt" />'
		+'		</horizontalAxis>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="방문자수"/>'
		+ '		</verticalAxis>'
		+'		<series>'
		+'			<Column2DSeries color="#666666" label="dt" font-weight="bold" yField="cnt" displayName="방문수" rotate="45">'
		+'				<fill>'
		+'					<SolidColor color="' + solidColor + '"/>'
		+'				</fill>'
		+'				<showDataEffect>'
		+'					<SeriesInterpolate/>'
		+'				</showDataEffect>'
		+'			</Column2DSeries>'
		+'		</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="true" canStagger="true"/>'
		+ '		</horizontalAxisRenderers>'
		+'	</Column2DChart>'
		+'</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartList);
};
